private class ProductionTree(private val loggingEnabled: Boolean) : Timber.Tree() {
    override fun isLoggable(tag: String?, priority: Int): Boolean {
        return loggingEnabled || priority >= Log.ERROR
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (!loggingEnabled && priority < Log.ERROR) return
        val safeTag = tag ?: "App"
        val finalMessage = buildString {
            append(message)
            if (t != null) {
                append('\n')
                append(getStackTraceString(t))
            }
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                append("")
            }
        }
        when (priority) {
            Log.VERBOSE -> Log.v(safeTag, finalMessage)
            Log.DEBUG -> Log.d(safeTag, finalMessage)
            Log.INFO -> Log.i(safeTag, finalMessage)
            Log.WARN -> Log.w(safeTag, finalMessage)
            Log.ERROR -> Log.e(safeTag, finalMessage)
            Log.ASSERT -> Log.wtf(safeTag, finalMessage)
            else -> Log.d(safeTag, finalMessage)
        }
    }
}

